import { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import styles from './Navbar.module.css';
import { cn } from '../lib/utils';

const Navbar = () => {
  const location = useLocation();

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Services', path: '/services' },
    { name: 'About', path: '/about' },
    { name: 'Contact', path: '/contact' },
  ];

  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const toggleMobileMenu = () => {
    setIsMobileMenuOpen(!isMobileMenuOpen);
  };

  const closeMobileMenu = () => {
    setIsMobileMenuOpen(false);
  };

  // Close mobile menu when route changes
  useEffect(() => {
    closeMobileMenu();
  }, [location.pathname]);

  // Lock body scroll when mobile menu is open
  useEffect(() => {
    if (isMobileMenuOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'auto';
    }
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, [isMobileMenuOpen]);

  return (
    <header className={styles.header}>
      <div className={cn('container', styles.inner)}>
        <Link to="/" className={styles.brand}>
          <img 
            alt="Logo" 
            src="https://lh3.googleusercontent.com/aida-public/AB6AXuDlvn4t0Je-IEFOp2MZ35GwH4S33wbtPcKsdmEiN7O6NQApLijEJPaLzBDub0lMnI9tHlNFHy9Gj0hn0aJW4BIwMvOGTsKWJcbAd1PEeWQQIJZL8eBRAgapt9rkIyd3djSY5oNPG6X5lPXrZr97Pz-LpK0QKSS1NY2YJTfCzUBdq-7H2lwE2VrsW1tLFfusWskUM5wbmjMc7AqI4hhX3Ukc5v2tYlXYNKv7VoOicztqy34CWtGhbJDtLCQta1f55Tk19WMoCzKPbaCK" 
          />
          <span className={styles.brandName}>
            Ferdjioua <span className="text-primary">Plastique</span>
          </span>
        </Link>

        <nav className={styles.nav}>
          {navLinks.map((link) => (
            <Link 
              key={link.name} 
              to={link.path} 
              className={cn(styles.navLink, location.pathname === link.path && styles.active)}
            >
              {link.name}
            </Link>
          ))}
        </nav>

        <div className={styles.actions}>
          <Link to="/contact" className={cn('btn btn-primary', styles.quoteBtn)}>
            Get a Quote
          </Link>
          <button className={styles.menuBtn} onClick={toggleMobileMenu} aria-label="Toggle menu">
            <span className="material-symbols-outlined">
              {isMobileMenuOpen ? 'close' : 'menu'}
            </span>
          </button>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      <div className={cn(styles.mobileMenu, isMobileMenuOpen && styles.mobileMenuOpen)}>
        <div className={styles.mobileNav}>
          {navLinks.map((link) => (
            <Link 
              key={link.name} 
              to={link.path} 
              className={cn(styles.mobileNavLink, location.pathname === link.path && styles.active)}
              onClick={closeMobileMenu}
            >
              {link.name}
            </Link>
          ))}
          <Link to="/contact" className="btn btn-primary w-full mt-4" onClick={closeMobileMenu}>
            Get a Quote
          </Link>
        </div>
      </div>
    </header>
  );
};

export default Navbar;

import type { ReactNode } from 'react';
import { motion } from 'framer-motion';

interface ScrollRevealProps {
  children: ReactNode;
  animation?: 'fade' | 'slide-up' | 'scale' | 'slide-left' | 'slide-right';
  delay?: number;
  duration?: number;
  className?: string;
  width?: 'fit-content' | '100%';
}

export const ScrollReveal = ({
  children,
  animation = 'slide-up',
  delay = 0,
  duration = 0.6,
  className,
  width = '100%'
}: ScrollRevealProps) => {

  const variants = {
    hidden: {
      opacity: 0,
      y: animation === 'slide-up' ? 30 : 0,
      x: animation === 'slide-left' ? 30 : animation === 'slide-right' ? -30 : 0,
      scale: animation === 'scale' ? 0.95 : 1,
    },
    visible: {
      opacity: 1,
      y: 0,
      x: 0,
      scale: 1,
      transition: {
        duration: duration,
        delay: delay,
        ease: "easeOut" as any,
      }
    }
  };

  return (
    <div style={{ width, position: 'relative' }} className={className}>
      <motion.div
        variants={variants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, margin: "-50px" }}
      >
        {children}
      </motion.div>
    </div>
  );
};

